('tech_house', 'Michael Bibi', 'United Kingdom', 'London', 'Michael Bibi e um DJ e produtor britanico de tech house, cofundador da Solid Grooves e ativo em lancamentos de 2025-2026 como Sungazing, Bad Wolf e Lets Get High.', 'tech house', 'Perfil reforcado com faixas tocaveis: Bad Wolf, Lets Get High, Front & Back Seat, Sungazing, Different Side, Got The Fire e Hanging Tree.', 'michael_bibi_playable_expansion_20260621', 'https://www.deezer.com/artist/5767953', 'published', '{"batch":"michael_bibi_playable_expansion_20260621","source_file":"data/michael_bibi_artist_profile_20260621.csv","confidence":"high","source_url":"https://www.deezer.com/artist/5767953","recent_release_focus":"Bad Wolf;Lets Get High;Front & Back Seat;Sungazing (Electronic Mix)","playable_track_count":53}'::jsonb)
on conflict (style, artist) do update set
  country = coalesce(excluded.country, public.catalog_artists.country),
  city = coalesce(excluded.city, public.catalog_artists.city),
  artist_bio = coalesce(excluded.artist_bio, public.catalog_artists.artist_bio),
  artist_genre = coalesce(excluded.artist_genre, public.catalog_artists.artist_genre),
  artist_profile_hint = coalesce(excluded.artist_profile_hint, public.catalog_artists.artist_profile_hint),
  source = excluded.source,
  source_url = coalesce(excluded.source_url, public.catalog_artists.source_url),
  status = case when public.catalog_artists.status = 'hidden' then public.catalog_artists.status else excluded.status end,
  metadata = coalesce(public.catalog_artists.metadata, '{}'::jsonb) || excluded.metadata;

