on conflict (style, artist, song) do update set
  label = coalesce(excluded.label, public.catalog_tracks.label),
  bpm_exact = coalesce(excluded.bpm_exact, public.catalog_tracks.bpm_exact),
  preview_url = coalesce(excluded.preview_url, public.catalog_tracks.preview_url),
  release_date = coalesce(excluded.release_date, public.catalog_tracks.release_date),
  duration_sec = coalesce(excluded.duration_sec, public.catalog_tracks.duration_sec),
  country = coalesce(excluded.country, public.catalog_tracks.country),
  city = coalesce(excluded.city, public.catalog_tracks.city),
  artist_bio = coalesce(excluded.artist_bio, public.catalog_tracks.artist_bio),
  artist_genre = coalesce(excluded.artist_genre, public.catalog_tracks.artist_genre),
  artist_profile_hint = coalesce(excluded.artist_profile_hint, public.catalog_tracks.artist_profile_hint),
  source = excluded.source,
  source_url = coalesce(excluded.source_url, public.catalog_tracks.source_url),
  status = case when public.catalog_tracks.status = 'hidden' then public.catalog_tracks.status else excluded.status end,
  metadata = coalesce(public.catalog_tracks.metadata, '{}'::jsonb) || excluded.metadata;
